const cfg = $("Valida Entrada").first().json || {};
const agent = $('Start').first().json.agent;
const agentName = clean(agent) || "Agente";
const agentNameNorm = norm(agentName);
const pageNames = [
  "Busca Página 1",
  "Busca Página 2",
  "Busca Página 3",
  "Busca Página 4",
  "Busca Página 5",
  "Busca Página 6"
];

function clean(value, preserveNewLines = false) {
  let text = "";

  if (value === undefined || value === null) {
    text = "";
  } else if (typeof value === "object") {
    try {
      text = JSON.stringify(value);
    } catch (error) {
      text = "";
    }
  } else {
    text = String(value);
  }

  text = text
    .replace(/\[object Object\]/gi, "")
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, " ")
    .replace(/\uFFFD/g, " ")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n");

  if (preserveNewLines) {
    return text
      .split("\n")
      .map(line => line.replace(/[ \t]+/g, " ").trim())
      .filter(Boolean)
      .join("\n")
      .trim();
  }

  return text.replace(/\s+/g, " ").trim();
}

function norm(value) {
  return clean(value)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();
}

function toNumberOrNull(value) {
  if (value === undefined || value === null || String(value).trim() === "") return null;
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function payloadFromNode(name) {
  try {
    const json = $(name).first().json || {};
    if (Array.isArray(json.payload)) return json.payload;
    if (Array.isArray(json.data?.payload)) return json.data.payload;
    if (Array.isArray(json.messages)) return json.messages;
    if (Array.isArray(json.data?.messages)) return json.data.messages;
    return [];
  } catch (error) {
    return [];
  }
}

function getAttachments(msg) {
  if (Array.isArray(msg?.attachments)) return msg.attachments;
  if (Array.isArray(msg?.files)) return msg.files;
  return [];
}

function getAttachmentKind(msg) {
  const first = getAttachments(msg)[0] || {};
  const fileType = String(
    first.file_type ||
    first.type ||
    first.content_type ||
    first.mime_type ||
    ""
  ).toLowerCase();

  if (fileType.includes("image")) return "image";
  if (fileType.includes("audio")) return "audio";
  if (fileType.includes("video")) return "video";
  if (fileType.includes("pdf")) return "document";
  if (fileType.includes("document")) return "document";
  if (fileType.includes("application")) return "document";

  return getAttachments(msg).length ? "attachment" : "";
}

function senderName(msg) {
  return clean(
    msg?.sender?.name ||
    msg?.sender?.available_name ||
    msg?.sender_name ||
    ""
  );
}

function senderType(msg) {
  return clean(
    msg?.sender?.type ||
    msg?.sender_type ||
    ""
  ).toLowerCase();
}

function isLeadMessage(msg) {
  return Number(msg?.message_type) === 0 || senderType(msg) === "contact";
}

function isOutgoingMessage(msg) {
  return Number(msg?.message_type) === 1;
}

function isSystemMessage(msg) {
  return Number(msg?.message_type) === 2;
}

function isPrivate(msg) {
  return msg?.private === true;
}

function isBotAgent(msg) {
  const name = norm(senderName(msg));
  const type = senderType(msg);

  return (
    type === "user" && (name === "convertix" || name === agentNameNorm)
  );
}

function isHumanAgent(msg) {
  const type = senderType(msg);
  return type === "user" && !isBotAgent(msg);
}

function isDeletedMessage(msg) {
  const content = norm(msg?.content || msg?.processed_message_content || "");

  return (
    msg?.content_attributes?.deleted === true ||
    content === "esta mensagem foi excluida" ||
    content === "mensagem excluida"
  );
}

function isInternalAudioTranscription(msg) {
  const content = String(msg?.content || msg?.processed_message_content || "");

  return (
    isOutgoingMessage(msg) &&
    isPrivate(msg) &&
    /\[TRANSCRIÇÃO INTERNA DO ÁUDIO/i.test(content)
  );
}

function extractAudioOriginalMessageId(msg) {
  const content = String(msg?.content || msg?.processed_message_content || "");

  const fromText = content.match(/msg_id\s+(\d+)/i);
  if (fromText?.[1]) return Number(fromText[1]);

  const fromReply = toNumberOrNull(msg?.content_attributes?.in_reply_to);
  if (fromReply) return fromReply;

  return null;
}

function extractAudioTranscriptionText(msg) {
  let text = String(msg?.content || msg?.processed_message_content || "");

  text = text
    .replace(/\[TRANSCRIÇÃO INTERNA DO ÁUDIO[^\]]*\]/gi, "")
    .replace(/⬇️\s*Transcrição do áudio\s*⬇️[^\n]*/gi, "")
    .replace(/- aproximadamente [^\n]*/gi, "");

  return clean(text, true);
}

function isTechnicalPrivateNote(msg) {
  const content = norm(msg?.content || msg?.processed_message_content || "");

  return (
    isPrivate(msg) &&
    (
      content.includes("auto aprendizado") ||
      content.includes("auto-aprendizado") ||
      content.includes(`conversa transcrita pela ${agentNameNorm} para auto-aprendizado`) ||
      content.includes(`${agentNameNorm} desligada nesta conversa`) ||
      content.includes(`${agentNameNorm} desligada na conversa`) ||
      content.includes(`${agentNameNorm} ligada nesta conversa`) ||
      content.includes(`${agentNameNorm} ligada na conversa`)
    )
  );
}

function isConvertixImportantPrivateNote(msg) {
  if (isInternalAudioTranscription(msg)) return false;

  const content = norm(msg?.content || msg?.processed_message_content || "");

  if (!isPrivate(msg)) return false;
  if (!isOutgoingMessage(msg)) return false;
  if (!isBotAgent(msg)) return false;

  const looksLikeFormNote =
    content.includes("chegou novo lead formulario") ||
    content.includes("respostas formulario") ||
    content.includes("-- respostas formulario --");

  const hasFormFields =
    content.includes("tipo hospedagem") ||
    content.includes("idade cao") ||
    content.includes("sexo:") ||
    content.includes("porte:") ||
    content.includes("raca:");

  const hasTrackingOrIdentity =
    content.includes("campanha:") ||
    content.includes("publico:") ||
    content.includes("anuncio:") ||
    content.includes("phone:") ||
    content.includes("nome:");

  return looksLikeFormNote || (hasFormFields && hasTrackingOrIdentity);
}

function isImportantSystemText(content) {
  return (
    content.includes("conversation was reopened") ||
    content.includes("conversation was resolved")
  );
}

function shouldDropSystemMessage(msg) {
  if (!isSystemMessage(msg)) return false;
  const content = norm(msg?.content || msg?.processed_message_content || "");

  return (
    !isImportantSystemText(content) ||
    content.includes("adicionou ") ||
    content.includes("removeu ") ||
    content.includes("atribuido") ||
    content.includes("atribuído") ||
    content.includes("por sistema de automacao") ||
    content.includes("por sistema de automação")
  );
}

function roleFromMessage(msg, originalMsgForTranscript = null) {
  if (isInternalAudioTranscription(msg)) {
    if (originalMsgForTranscript && isLeadMessage(originalMsgForTranscript)) return "lead";
    if (originalMsgForTranscript && isBotAgent(originalMsgForTranscript)) return "agent";
    if (originalMsgForTranscript && isHumanAgent(originalMsgForTranscript)) return "humano";
    if (originalMsgForTranscript && isOutgoingMessage(originalMsgForTranscript)) return "humano";

    return "lead";
  }

  if (isConvertixImportantPrivateNote(msg)) return "nota_convertix";
  if (isLeadMessage(msg)) return "lead";
  if (isSystemMessage(msg)) return "sistema";

  if (isOutgoingMessage(msg)) {
    if (isBotAgent(msg)) return "agent";
    if (isHumanAgent(msg) && isPrivate(msg)) return "nota_humana";
    if (isHumanAgent(msg)) return "humano";
    if (isPrivate(msg)) return "nota_interna";
    return "agent";
  }

  return "sistema";
}

function roleLabel(role) {
  if (role === "lead") return "Lead";
  if (role === "agent") return agentName;
  if (role === "humano") return "Humano";
  if (role === "nota_humana") return "Nota Humana";
  if (role === "nota_convertix") return "Nota Convertix";
  return "Sistema";
}

function contentForAttachmentOnly(msg, role) {
  const kind = getAttachmentKind(msg) || "anexo";
  const id = toNumberOrNull(msg?.id);

  if (role === "lead") return `[ANEXO ${kind} recebido do lead | message_id: ${id || ""}]`;
  if (role === "humano" || role === "agent") return `[ANEXO ${kind} enviado | message_id: ${id || ""}]`;

  return `[ANEXO ${kind} | message_id: ${id || ""}]`;
}

function isAttachmentPlaceholderText(value) {
  const t = norm(value);

  return (
    /^\[anexo\s+.+\|?\s*message_id:?\s*\d*\]$/.test(t) ||
    t.startsWith("[anexo ") ||
    t === "[audio recebido do lead]" ||
    t === "[áudio recebido do lead]"
  );
}

function isRelevantText(text, role) {
  const t = clean(text);
  if (!t) return false;
  if (/^(ok|obrigado|obrigada|obg|valeu|👍|👌|🙏|❤️|❤|kkk|rs|rsrs)$/i.test(t)) return false;
  if (/^esta mensagem foi exclu[ií]da$/i.test(t)) return false;
  if (role === "sistema") return false;
  return true;
}

function normalizeMessage(msg, rawMessageMap) {
  const isTranscript = isInternalAudioTranscription(msg);
  const referencedId = isTranscript ? extractAudioOriginalMessageId(msg) : null;
  const originalMsg = referencedId ? rawMessageMap.get(referencedId) : null;

  const id = isTranscript
    ? referencedId || toNumberOrNull(msg?.id)
    : toNumberOrNull(msg?.id);

  const role = roleFromMessage(msg, originalMsg);
  const originalContent = isTranscript
    ? extractAudioTranscriptionText(msg)
    : clean(msg?.processed_message_content || msg?.content || "", true);

  const metaSource = isTranscript && originalMsg ? originalMsg : msg;
  const hasAttachment = getAttachments(metaSource).length > 0;
  const attachmentKind = getAttachmentKind(metaSource) || "";
  const hasRealText = Boolean(originalContent) && !isAttachmentPlaceholderText(originalContent);

  let content = originalContent;
  if (!content || (hasAttachment && isAttachmentPlaceholderText(content) && !hasRealText)) {
    content = contentForAttachmentOnly(msg, role);
  }

  if (isTranscript) {
    content = originalContent;
  }

  return {
    id,
    content,
    role,
    role_label: roleLabel(role),
    private: metaSource?.private === true,
    message_type: metaSource?.message_type ?? null,
    sender_name: senderName(metaSource),
    created_at: metaSource?.created_at || metaSource?.updated_at || msg?.created_at || msg?.updated_at || null,
    has_attachment: hasAttachment,
    attachment_kind: attachmentKind,
    is_audio_transcription: isTranscript,
    original_transcription_note_id: isTranscript ? toNumberOrNull(msg?.id) : null
  };
}

function formatLine(msg) {
  const content = clean(msg.content, true);
  if (!content) return "";
  return `[${msg.id}] ${msg.role_label}: ${content}`;
}

const rawMessages = pageNames.flatMap(payloadFromNode);
const rawById = new Map();

for (const raw of rawMessages) {
  const messageId = toNumberOrNull(raw?.id);
  if (!messageId) continue;
  rawById.set(messageId, raw);
}

const uniqueRawMessages = Array.from(rawById.values())
  .sort((a, b) => Number(a.id) - Number(b.id));

const transcribedOriginalIds = new Set();

for (const msg of uniqueRawMessages) {
  if (!isInternalAudioTranscription(msg)) continue;
  const originalId = extractAudioOriginalMessageId(msg);
  if (originalId) transcribedOriginalIds.add(originalId);
}

let normalized = uniqueRawMessages
  .filter(msg => !isDeletedMessage(msg))
  .filter(msg => !isTechnicalPrivateNote(msg))
  .filter(msg => !shouldDropSystemMessage(msg))
  .filter(msg => {
    const messageId = toNumberOrNull(msg?.id);
    if (!messageId) return false;
    if (isInternalAudioTranscription(msg)) return true;
    if (transcribedOriginalIds.has(messageId) && getAttachmentKind(msg) === "audio") return false;
    return true;
  })
  .map(msg => normalizeMessage(msg, rawById))
  .filter(msg => msg.id !== null && msg.id !== undefined)
  .filter(msg => msg.role !== "nota_interna")
  .filter(msg => msg.role !== "sistema")
  .filter(msg => isRelevantText(msg.content, msg.role) || msg.has_attachment || msg.is_audio_transcription)
  .sort((a, b) => Number(a.id) - Number(b.id));

const normalizedById = new Map();

for (const msg of normalized) {
  normalizedById.set(Number(msg.id), msg);
}

normalized = Array.from(normalizedById.values())
  .sort((a, b) => Number(a.id) - Number(b.id));

const limit = Math.min(Math.max(Number(cfg.qtd_messages || 40), 1), 120);
const selected = normalized.slice(-limit);
const historyText = selected.map(formatLine).filter(Boolean).join("\n");

return [{
  json: {
    agent: agentName,
    agent_norm: agentNameNorm,
    account_id: cfg.account_id,
    conversation_id: cfg.conversation_id,
    qtd_messages_requested: cfg.qtd_messages_requested,
    qtd_messages_used: limit,
    max_messages: 120,
    messages_found_total: normalized.length,
    messages_returned: selected.length,
    history_text: historyText,
    history_for_agent: historyText
      ? [
          `HISTÓRICO RECENTE DA CONVERSA (últimas ${selected.length} mensagens):`,
          historyText
        ].join("\n")
      : "HISTÓRICO RECENTE DA CONVERSA: sem mensagens encontradas.",
    messages: selected,
    debug: {
      workflow: `chatwoot_busca_historico_${agentNameNorm}`,
      logic_version: `v2_prepara_contexto_audio_roles_${agentNameNorm}`,
      pages_requested: pageNames.length,
      raw_messages_received: rawMessages.length,
      unique_messages: rawById.size,
      transcribed_audio_originals: Array.from(transcribedOriginalIds),
      system_messages_removed: uniqueRawMessages.filter(shouldDropSystemMessage).length,
      deleted_messages_removed: uniqueRawMessages.filter(isDeletedMessage).length,
      technical_notes_removed: uniqueRawMessages.filter(isTechnicalPrivateNote).length,
      generated_at: new Date().toISOString()
    }
  }
}];

