const conversationId = toPositiveInt(input.conversation_id, 0);
const qtdMessagesRaw = toPositiveInt(input.qtd_messages, 40);
const qtdMessages = Math.min(Math.max(qtdMessagesRaw, 1), 120);

if (!accountId) {
  throw new Error("account_id obrigatório para buscar histórico no Chatwoot.");
}

if (!conversationId) {
  throw new Error("conversation_id obrigatório para buscar histórico no Chatwoot.");
}

